// ─── SectionHeader (used inside LetterheadSetup) ──────────────────────────────
function SectionHeader({ num, title }) {
  return (
    <div className="section-header">
      <span className="sec-num">{num}</span>
      <span className="sec-title">{title}</span>
    </div>
  );
}

