// u2500u2500u2500 Core Designer Logic 
function createDesigner(rootEl) {
  const SNAP = 10;
  const STORE_KEY = 'lhd_designs_v1';
  let elements = [], selId = null, nextId = 1, zoom = 0.75, gridOn = false;
  let dragging = false, dragDiv = null, dragOX = 0, dragOY = 0;
  let resizing = false, resEl = null, resX0 = 0, resY0 = 0, resW0 = 0, resH0 = 0;
  let autoSaveTimer = null, currentSaveName = null;
  let _paper, _propPanel, _elList, _saveChips, _savesList2;

  const DEF = {
    company:   { type:'company',   label:'Company Name',  x:200,y:30,  w:390,h:52,  text:'NEO CIVIC CONSULTING PVT. LTD', font:"'Comic Sans MS',cursive",       size:18,weight:'700',color:'#000000',useGrad:false,grad:{stops:[{c:'#c8700a',p:0},{c:'#1a3a5c',p:100}],angle:90,type:'linear'},align:'center'},
    address:   { type:'address',   label:'Address',       x:220,y:88,  w:350,h:46,  text:'Banasthali\nKathmandu',         font:"'Comic Sans MS',cursive",       size:16,weight:'700',color:'#000000',useGrad:false,grad:{stops:[{c:'#c8700a',p:0},{c:'#000000',p:100}],angle:90,type:'linear'},align:'center'},
    pan:       { type:'pan',       label:'PAN/VAT No.',   x:580,y:32,  w:190,h:20,  text:'PAN/VAT No.: 604231561',        font:"'Source Sans 3',sans-serif",    size:10,weight:'700',color:'#000000',useGrad:false,grad:{stops:[{c:'#c8700a',p:0},{c:'#000',p:100}],angle:0,type:'linear'},align:'right'},
    reg:       { type:'reg',       label:'Regd. No.',     x:580,y:12,  w:190,h:20,  text:'Regd. No: 146498/072-073',      font:"'Source Sans 3',sans-serif",    size:10,weight:'700',color:'#000000',useGrad:false,grad:{stops:[{c:'#c8700a',p:0},{c:'#000',p:100}],angle:0,type:'linear'},align:'right'},
    logo:      { type:'logo',      label:'Logo',          x:20, y:18,  w:82, h:82,  src:null },
    watermark: { type:'watermark', label:'Watermark',     x:147,y:200, w:500,h:500, src:null, opacity:0.08 },
    divider:   { type:'divider',   label:'Divider Line',  x:20, y:150, w:754,h:7,   color1:'#c8700a',color2:'#000000',lines:2,thick:2 },
    text:      { type:'text',      label:'Custom Text',   x:100,y:250, w:220,h:32,  text:'Your text here', font:"'Source Sans 3',sans-serif", size:13,weight:'400',color:'#333333',useGrad:false,grad:{stops:[{c:'#c8700a',p:0},{c:'#1a3a5c',p:100}],angle:90,type:'linear'},align:'left'},
  };

  const PRESETS = [
    ['Goldâ†’Blue','linear',90,[{c:'#c8700a',p:0},{c:'#1a3a5c',p:100}]],
    ['Orangeâ†’Red','linear',90,[{c:'#f39c12',p:0},{c:'#e74c3c',p:100}]],
    ['Tealâ†’Purple','linear',135,[{c:'#1abc9c',p:0},{c:'#9b59b6',p:100}]],
    ['Blackâ†’Gold','linear',0,[{c:'#000',p:0},{c:'#c8700a',p:100}]],
    ['Navyâ†’Sky','linear',90,[{c:'#1a3a5c',p:0},{c:'#3498db',p:100}]],
    ['Greenâ†’Teal','linear',90,[{c:'#27ae60',p:0},{c:'#16a085',p:100}]],
    ['Redâ†’Orange','linear',90,[{c:'#c0392b',p:0},{c:'#e67e22',p:100}]],
    ['3-Color','linear',90,[{c:'#c8700a',p:0},{c:'#1a3a5c',p:50},{c:'#c8700a',p:100}]],
  ];

  const deepCopy = o => JSON.parse(JSON.stringify(o));
  const getEl = id => elements.find(e => e.id === id) || null;
  const q = (sel, ctx) => (ctx || rootEl).querySelector(sel);
  const qa = (sel, ctx) => (ctx || rootEl).querySelectorAll(sel);
  const esc = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  const buildGradCss = g => {
    const stops = g.stops.map(s => `${s.c} ${s.p}%`).join(', ');
    return g.type === 'radial' ? `radial-gradient(circle, ${stops})` : `linear-gradient(${g.angle}deg, ${stops})`;
  };

  function buildInner(el) {
    if (el.type === 'watermark') return `<img src="${el.src||LOGO_B64}" style="width:100%;height:100%;object-fit:contain;opacity:${el.opacity};display:block;" draggable="false">`;
    if (el.type === 'logo')      return `<img src="${el.src||LOGO_B64}" style="width:100%;height:100%;object-fit:contain;display:block;" draggable="false">`;
    if (el.type === 'divider') {
      const h = el.thick + 'px';
      let s = `<div style="height:${h};background:${el.color1};border-radius:1px;"></div>`;
      if (el.lines === 2) s += `<div style="height:${h};background:${el.color2};border-radius:1px;margin-top:3px;"></div>`;
      return s;
    }
    const lines = (el.text||'').split('\n').map(l => `<div>${esc(l)}</div>`).join('');
    const aln = el.align === 'right' ? 'right' : el.align === 'center' ? 'center' : 'left';
    const gStyle = el.useGrad
      ? `background:${buildGradCss(el.grad)};-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;`
      : `color:${el.color};`;
    return `<div class="lhd-inner" style="font-family:${el.font};font-size:${el.size}px;font-weight:${el.weight};text-align:${aln};line-height:1.35;white-space:pre;${gStyle}">${lines}</div>`;
  }

  function renderElOnPaper(el) {
    const div = document.createElement('div');
    div.className = 'lhd-el' + (el.id === selId ? ' lhd-sel' : '');
    div.id = 'lhd-el-' + el.id;
    div.setAttribute('data-id', el.id);
    div.style.left = el.x + 'px'; div.style.top = el.y + 'px'; div.style.width = el.w + 'px';
    if (['watermark','logo','divider'].includes(el.type)) div.style.height = el.h + 'px';
    div.style.zIndex = el.type==='watermark'?'0':el.type==='logo'?'5':el.type==='divider'?'3':'4';
    div.innerHTML = buildInner(el) + '<div class="lhd-ring"></div><div class="lhd-rh" data-id="' + el.id + '"></div>';
    div.addEventListener('mousedown', onElMD);
    div.querySelector('.lhd-rh').addEventListener('mousedown', onRhMD);
    _paper.appendChild(div);
  }

  function renderAll() {
    _paper.querySelectorAll('.lhd-el').forEach(d => d.remove());
    elements.forEach(renderElOnPaper);
    renderElList();
  }

  function refreshEl(el) {
    const div = document.getElementById('lhd-el-' + el.id); if (!div) return;
    div.style.left = el.x+'px'; div.style.top = el.y+'px'; div.style.width = el.w+'px';
    if (['watermark','logo','divider'].includes(el.type)) div.style.height = el.h+'px';
    const ring = div.querySelector('.lhd-ring'), rh = div.querySelector('.lhd-rh');
    div.innerHTML = buildInner(el);
    div.appendChild(ring); div.appendChild(rh);
  }

  function onElMD(e) {
    if (e.target.classList.contains('lhd-rh')) return;
    e.preventDefault(); e.stopPropagation();
    selectEl(parseInt(this.getAttribute('data-id')));
    dragging = true; dragDiv = this;
    const r = dragDiv.getBoundingClientRect();
    dragOX = (e.clientX - r.left) / zoom; dragOY = (e.clientY - r.top) / zoom;
    dragDiv.style.cursor = 'grabbing';
  }
  function onRhMD(e) {
    e.preventDefault(); e.stopPropagation();
    const id = parseInt(e.target.getAttribute('data-id'));
    selectEl(id); resizing = true; resEl = getEl(id);
    resX0 = e.clientX; resY0 = e.clientY; resW0 = resEl.w; resH0 = resEl.h;
  }
  function onMouseMove(e) {
    if (dragging && dragDiv) {
      const pr = _paper.getBoundingClientRect();
      let nx = (e.clientX - pr.left) / zoom - dragOX, ny = (e.clientY - pr.top) / zoom - dragOY;
      if (q('#lhd-snapCb').checked) { nx = Math.round(nx/SNAP)*SNAP; ny = Math.round(ny/SNAP)*SNAP; }
      const el = getEl(parseInt(dragDiv.getAttribute('data-id')));
      if (el) { el.x=nx; el.y=ny; dragDiv.style.left=nx+'px'; dragDiv.style.top=ny+'px'; updatePropXY(el); }
      scheduleAutoSave();
    }
    if (resizing && resEl) {
      let nw = Math.max(20, resW0+(e.clientX-resX0)/zoom), nh = Math.max(10, resH0+(e.clientY-resY0)/zoom);
      if (q('#lhd-snapCb').checked) { nw = Math.round(nw/SNAP)*SNAP; nh = Math.round(nh/SNAP)*SNAP; }
      resEl.w = nw; resEl.h = nh;
      const div = document.getElementById('lhd-el-'+resEl.id);
      if (div) { div.style.width=nw+'px'; if(['watermark','logo','divider'].includes(resEl.type)) div.style.height=nh+'px'; }
      updatePropWH(resEl); scheduleAutoSave();
    }
  }
  function onMouseUp() {
    if (dragging) { dragging=false; if(dragDiv){dragDiv.style.cursor='move';dragDiv=null;} renderElList(); }
    if (resizing) { resizing=false; resEl=null; }
  }

  function selectEl(id) {
    selId = id;
    qa('.lhd-el').forEach(d => d.classList.toggle('lhd-sel', parseInt(d.getAttribute('data-id'))===id));
    qa('.lhd-el-item').forEach(d => d.classList.toggle('lhd-sel', parseInt(d.getAttribute('data-id'))===id));
    showProps(id);
    switchTab(qa('.lhd-stab')[1], 'props');
  }
  function deselectAll() {
    selId = null;
    qa('.lhd-el,.lhd-el-item').forEach(d => d.classList.remove('lhd-sel'));
    _propPanel.innerHTML = '<div style="padding:24px;text-align:center;color:#444;font-size:.82rem;"><div style="font-size:2rem;margin-bottom:8px;">âœï¸</div>Click an element to edit</div>';
  }

  function showProps(id) {
    const el = getEl(id); if (!el) return;
    let h = `<div class="lhd-sec"><div class="lhd-sec-h" style="pointer-events:none;color:#c8700a;">${el.label}</div><div class="lhd-sec-b">`;
    h += '<div class="lhd-row4">';
    ['x','y','w','h'].forEach(k => {
      h += `<div><label>${k.toUpperCase()}</label><input id="lhd-p${k}" class="lhd-si" type="number" value="${Math.round(el[k])}" onchange="window.__lhd_setProp('${k}',+this.value)"></div>`;
    });
    h += '</div>';
    if (['text','company','address','pan','reg'].includes(el.type)) {
      h += `<div class="lhd-field"><label>Text</label><textarea class="lhd-si" rows="3" onchange="window.__lhd_setProp('text',this.value)">${el.text}</textarea></div>`;
      h += '<div class="lhd-row3">';
      h += '<div><label>Font</label><select class="lhd-si" onchange="window.__lhd_setProp(\'font\',this.value)">';
      [["'Comic Sans MS',cursive","Comic Sans"],["'Source Sans 3',sans-serif","Source Sans"],["'Montserrat',sans-serif","Montserrat"],["'Lato',sans-serif","Lato"],["'Merriweather',serif","Merriweather"],["Arial,sans-serif","Arial"],["'Times New Roman',serif","Times NR"]]
        .forEach(f => { h += `<option value="${f[0]}"${el.font===f[0]?' selected':''}>${f[1]}</option>`; });
      h += '</select></div>';
      h += `<div><label>Size</label><input class="lhd-si" type="number" value="${el.size}" min="6" max="120" onchange="window.__lhd_setProp('size',+this.value)"></div>`;
      h += '<div><label>Weight</label><select class="lhd-si" onchange="window.__lhd_setProp(\'weight\',this.value)">';
      [{v:'300',l:'Light'},{v:'400',l:'Normal'},{v:'600',l:'Semi'},{v:'700',l:'Bold'},{v:'900',l:'Black'}]
        .forEach(w => { h += `<option value="${w.v}"${el.weight===w.v?' selected':''}>${w.l}</option>`; });
      h += '</select></div></div>';
      h += `<div class="lhd-field"><label>Align</label><select class="lhd-si" onchange="window.__lhd_setProp('align',this.value)"><option value="left"${el.align==='left'?' selected':''}>Left</option><option value="center"${el.align==='center'?' selected':''}>Center</option><option value="right"${el.align==='right'?' selected':''}>Right</option></select></div>`;
      h += `<div class="lhd-tr"><span class="lhd-tl">Use Gradient Text</span><label class="lhd-toggle"><input type="checkbox" id="lhd-useGradCb"${el.useGrad?' checked':''} onchange="window.__lhd_setProp('useGrad',this.checked)"><span class="lhd-tsl"></span></label></div>`;
      h += `<div id="lhd-solidBlock" style="${el.useGrad?'display:none':''}"><div class="lhd-cr"><label>Solid Color</label><input type="color" value="${el.color}" oninput="window.__lhd_setProp('color',this.value)"></div></div>`;
      h += `<div id="lhd-gradBlock" style="${el.useGrad?'':'display:none'}">${buildGradEditorHTML(el)}</div>`;
    }
    if (el.type === 'logo' || el.type === 'watermark') {
      h += `<div class="lhd-field"><label>Image</label><div style="background:#1d1d1d;border:1px solid #2d2d2d;border-radius:4px;padding:8px;text-align:center;cursor:pointer;" onclick="document.getElementById('lhd-imgUp_${id}').click()"><input type="file" id="lhd-imgUp_${id}" accept="image/*" style="display:none" onchange="window.__lhd_uploadImg(${id},this)"><p style="font-size:.72rem;color:#777;">ðŸ“· Click to upload</p></div></div>`;
      if (el.type === 'watermark') h += `<div class="lhd-rr"><div><label>Opacity</label><input type="range" min="1" max="30" value="${Math.round(el.opacity*100)}" oninput="window.__lhd_setProp('opacity',this.value/100);document.getElementById('lhd-opV').textContent=this.value+'%'"></div><span id="lhd-opV">${Math.round(el.opacity*100)}%</span></div>`;
      h += `<button class="lhd-btn lhd-btn-o lhd-sm" style="width:100%;margin-top:4px" onclick="window.__lhd_resetImg(${id})">â†º Reset</button>`;
    }
    if (el.type === 'divider') {
      h += `<div class="lhd-row2"><div><label>Line 1 Color</label><input type="color" value="${el.color1}" oninput="window.__lhd_setProp('color1',this.value)"></div><div><label>Line 2 Color</label><input type="color" value="${el.color2}" oninput="window.__lhd_setProp('color2',this.value)"></div></div>`;
      h += `<div class="lhd-row2"><div><label>Lines</label><select class="lhd-si" onchange="window.__lhd_setProp('lines',+this.value)"><option value="1"${el.lines===1?' selected':''}>1 Line</option><option value="2"${el.lines===2?' selected':''}>2 Lines</option></select></div><div><label>Thickness</label><input class="lhd-si" type="number" value="${el.thick}" min="1" max="12" onchange="window.__lhd_setProp('thick',+this.value)"></div></div>`;
    }
    h += `<div class="lhd-row2" style="margin-top:10px;"><button class="lhd-btn lhd-btn-o lhd-sm" onclick="window.__lhd_dupEl(${id})">â§‰ Duplicate</button><button class="lhd-btn lhd-btn-r lhd-sm" onclick="window.__lhd_delEl(${id})">âœ• Delete</button></div>`;
    h += '</div></div>';
    _propPanel.innerHTML = h;
  }

  function buildGradEditorHTML(el) {
    const g = el.grad;
    let h = `<div class="lhd-grad-box"><div class="lhd-grad-prev" id="lhd-gradPrev_${el.id}" style="background:${buildGradCss(g)};"></div><div class="lhd-grad-stops">`;
    g.stops.forEach((s,i) => {
      h += `<div class="lhd-gsr"><input type="color" value="${s.c}" oninput="window.__lhd_gradStopColor(${i},this.value)"><input type="range" min="0" max="100" value="${s.p}" oninput="window.__lhd_gradStopPos(${i},+this.value)"><span>${s.p}%</span><button onclick="window.__lhd_removeGradStop(${i})">âœ•</button></div>`;
    });
    h += `</div><div class="lhd-grad-ctrl"><button onclick="window.__lhd_addGradStop()">+ Stop</button><select onchange="window.__lhd_gradType(this.value)"><option value="linear"${g.type==='linear'?' selected':''}>Linear</option><option value="radial"${g.type==='radial'?' selected':''}>Radial</option></select><span style="font-size:.64rem;color:#666;display:flex;align-items:center;gap:4px;">Angle <input type="number" value="${g.angle}" min="0" max="360" style="width:38px;padding:2px 4px;border:1px solid #2d2d2d;border-radius:3px;font-size:.68rem;background:#222;color:#ddd;" onchange="window.__lhd_gradAngle(+this.value)">Â°</span></div>`;
    h += '<div style="font-size:.62rem;color:#555;margin-bottom:4px;margin-top:6px;">PRESETS</div><div class="lhd-grad-presets">';
    PRESETS.forEach((pr,i) => {
      const stops = pr[3].map(s => `${s.c} ${s.p}%`).join(', ');
      h += `<div class="lhd-preset-swatch" title="${pr[0]}" style="background:linear-gradient(90deg,${stops})" onclick="window.__lhd_applyPreset(${i})"></div>`;
    });
    h += '</div></div>';
    return h;
  }

  function updatePropXY(el) {
    const a=q('#lhd-px'),b=q('#lhd-py');
    if(a)a.value=Math.round(el.x); if(b)b.value=Math.round(el.y);
  }
  function updatePropWH(el) {
    const a=q('#lhd-pw'),b=q('#lhd-ph');
    if(a)a.value=Math.round(el.w); if(b)b.value=Math.round(el.h);
  }
  function refreshGradPrev(el) {
    const p = q('#lhd-gradPrev_'+el.id); if(p) p.style.background = buildGradCss(el.grad);
  }

  function renderElList() {
    if (!_elList) return;
    _elList.innerHTML = '';
    elements.forEach(el => {
      const d = document.createElement('div');
      d.className = 'lhd-el-item' + (el.id===selId?' lhd-sel':'');
      d.setAttribute('data-id', el.id);
      d.innerHTML = DOMPurify.sanitize(`<div><div class="lhd-el-name">${el.label}</div><div class="lhd-el-type">${el.type} Â· x:${Math.round(el.x)} y:${Math.round(el.y)}</div></div><div class="lhd-el-acts"><button class="lhd-ea" onclick="event.stopPropagation();window.__lhd_dupEl(${el.id})">â§‰</button><button class="lhd-ea lhd-del" onclick="event.stopPropagation();window.__lhd_delEl(${el.id})">âœ•</button></div>`);
      d.addEventListener('click', () => selectEl(el.id));
      _elList.appendChild(d);
    });
  }

  function addEl(type) {
    const def = DEF[type]||DEF.text;
    const el = deepCopy(def); el.id=nextId++; el.x=40+(elements.length%6)*18; el.y=40+(elements.length%6)*18;
    elements.push(el); renderElOnPaper(el); renderElList(); selectEl(el.id); scheduleAutoSave();
  }
  function delEl(id) {
    elements = elements.filter(e => e.id!==id);
    const d = document.getElementById('lhd-el-'+id); if(d) d.remove();
    if(selId===id) deselectAll(); renderElList(); scheduleAutoSave();
  }
  function dupEl(id) {
    const src = getEl(id); if(!src) return;
    const copy = deepCopy(src); copy.id=nextId++; copy.x+=18; copy.y+=18;
    elements.push(copy); renderElOnPaper(copy); renderElList(); selectEl(copy.id); scheduleAutoSave();
  }

  const getStore = () => { try { return JSON.parse(sessionStorage.getItem(STORE_KEY)||'{}'); } catch(e) { return {}; } };
  const putStore = d => { try { sessionStorage.setItem(STORE_KEY,JSON.stringify(d)); } catch(e) { showToast('Storage error'); } };
  const getState = () => ({ elements, nextId, paperSz:q('#lhd-paperSz').value, paperBg:q('#lhd-paperBg').value, savedAt:new Date().toISOString() });
  function loadState(s) {
    elements=s.elements||[]; nextId=s.nextId||elements.length+1;
    q('#lhd-paperSz').value=s.paperSz||'lhd-a4'; q('#lhd-paperBg').value=s.paperBg||'#ffffff';
    updatePaper(); renderAll(); deselectAll();
  }
  function scheduleAutoSave() {
    clearTimeout(autoSaveTimer);
    autoSaveTimer = setTimeout(() => {
      const store=getStore(); store[currentSaveName||'autosave']=getState(); putStore(store);
      renderSavesBar(); renderSavesList2();
    }, 1200);
  }
  function saveDesign() {
    const name = prompt('Name for this design:', currentSaveName||'My Letterhead'); if(!name) return;
    currentSaveName=name; const store=getStore(); store[name]=getState(); putStore(store);
    renderSavesBar(); renderSavesList2(); showToast(`Saved "${name}"!`);
  }
  function loadSave(name) {
    const state=getStore()[name]; if(!state){showToast('Not found.');return;}
    currentSaveName=name; loadState(state); renderSavesBar(); renderSavesList2(); showToast(`Loaded "${name}"`);
  }
  function deleteSave(name) {
    if(!confirm(`Delete "${name}"?`)) return;
    const store=getStore(); delete store[name]; putStore(store);
    if(currentSaveName===name) currentSaveName=null;
    renderSavesBar(); renderSavesList2();
  }
  function renderSavesBar() {
    if(!_saveChips) return;
    const store=getStore(), keys=Object.keys(store);
    if(!keys.length){_saveChips.innerHTML='<span class="lhd-no-saves">No saved designs yet</span>';return;}
    _saveChips.innerHTML='';
    keys.forEach(name => {
      const d=document.createElement('div');
      d.className='lhd-chip'+(currentSaveName===name?' lhd-active-save':'');
      d.innerHTML=DOMPurify.sanitize(`<span onclick="window.__lhd_loadSave('${name.replace(/'/g,"\\'")}')">  ${name}</span><span class="lhd-del-chip" onclick="window.__lhd_deleteSave('${name.replace(/'/g,"\\'")}')">âœ•</span>`);
      _saveChips.appendChild(d);
    });
  }
  function renderSavesList2() {
    if(!_savesList2) return;
    const store=getStore(), keys=Object.keys(store);
    if(!keys.length){_savesList2.innerHTML='<div style="font-size:.72rem;color:#444;font-style:italic;">No saved designs yet.</div>';return;}
    _savesList2.innerHTML='';
    keys.forEach(name => {
      const state=store[name], d=new Date(state.savedAt);
      const ts=d.toLocaleDateString()+' '+d.toLocaleTimeString(undefined,{hour:'2-digit',minute:'2-digit'});
      const row=document.createElement('div'); row.className='lhd-save-row';
      row.innerHTML=DOMPurify.sanitize(`<div><div class="lhd-save-row-name">${name}</div><div class="lhd-save-row-ts">${ts}</div></div><div style="display:flex;gap:4px;"><button class="lhd-ea" onclick="window.__lhd_loadSave('${name.replace(/'/g,"\\'")}')">â†µ Load</button><button class="lhd-ea lhd-del" onclick="window.__lhd_deleteSave('${name.replace(/'/g,"\\'")}')" >âœ•</button></div>`);
      _savesList2.appendChild(row);
    });
  }

  function setZoom(v) {
    zoom=v/100;
    const po=q('#lhd-paperOuter');
    po.style.transform=`scale(${zoom})`; po.style.transformOrigin='top center';
    po.style.marginBottom=(_paper.offsetHeight*zoom-_paper.offsetHeight)+'px';
    q('#lhd-zoomV').textContent=Math.round(v)+'%'; q('#lhd-zoomR').value=v;
    qa('.lhd-csb').forEach(b => b.classList.remove('lhd-active'));
    const lbl={50:'50%',75:'75%',100:'100%'}[parseInt(v)];
    if(lbl) qa('.lhd-csb').forEach(b => { if(b.textContent===lbl) b.classList.add('lhd-active'); });
  }
  function toggleGrid() {
    gridOn=!gridOn;
    q('#lhd-gridOv').classList.toggle('lhd-show',gridOn);
    q('#lhd-gridCb').checked=gridOn;
  }
  function updatePaper() {
    _paper.classList.remove('lhd-a4','lhd-letter');
    _paper.classList.add(q('#lhd-paperSz').value);
    _paper.style.background=q('#lhd-paperBg').value;
    scheduleAutoSave();
  }
  function resetAll() {
    if(!confirm('Reset to default layout?')) return;
    elements=[]; nextId=1; selId=null; currentSaveName=null;
    _paper.querySelectorAll('.lhd-el').forEach(d=>d.remove());
    initDefaultElements(); renderElList(); deselectAll();
  }
  function downloadHTML() {
    const p=_paper.cloneNode(true);
    p.style.transform=''; p.style.marginBottom='';
    p.querySelectorAll('.lhd-ring,.lhd-rh,.lhd-grid').forEach(e=>e.remove());
    p.querySelectorAll('.lhd-el').forEach(d=>d.style.cursor='default');
    const html=`<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Letterhead</title><link href="https://fonts.googleapis.com/css2?family=Comic+Sans+MS&family=Source+Sans+3:wght@300;400;600&family=Montserrat:wght@400;600;700&family=Lato:wght@300;400;700&display=swap" rel="stylesheet"><style>*{box-sizing:border-box;margin:0;padding:0}body{background:#ccc;display:flex;justify-content:center;padding:40px}.lhd-paper{background:#fff;position:relative;overflow:hidden;box-shadow:0 4px 32px rgba(0,0,0,.2)}.lhd-paper.lhd-a4{width:794px;height:1123px}.lhd-paper.lhd-letter{width:816px;height:1056px}.lhd-el{position:absolute}.lhd-inner{-webkit-background-clip:text;background-clip:text;}</style></head><body>${p.outerHTML}</body></html>`;
    const blob=new Blob([html],{type:'text/html'});
    const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='letterhead.html'; a.click();
    showToast('Downloaded!');
  }
  function showToast(msg) {
    let t=document.getElementById('lhd-toast-el')||document.createElement('div');
    t.id='lhd-toast-el'; t.className='lhd-toast'; t.textContent=msg;
    document.body.appendChild(t); clearTimeout(t._t); t.style.opacity='1';
    t._t=setTimeout(()=>{t.style.opacity='0';setTimeout(()=>t.remove(),400);},2200);
  }
  function switchTab(el, name) {
    qa('.lhd-stab').forEach(t=>t.classList.remove('lhd-active')); el.classList.add('lhd-active');
    ['elements','props','page'].forEach(n=>{ const d=q('#lhd-tab-'+n); if(d) d.style.display=n===name?'block':'none'; });
  }
  function toggleSec(h) { h.classList.toggle('lhd-collapsed'); h.nextElementSibling.classList.toggle('lhd-hidden'); }

  function setProp(k,v) {
    const el=getEl(selId); if(!el) return;
    el[k]=v; refreshEl(el); updatePropXY(el); updatePropWH(el);
    if(k==='useGrad'){
      const gb=q('#lhd-gradBlock'),sb=q('#lhd-solidBlock');
      if(gb) gb.style.display=v?'':'none'; if(sb) sb.style.display=v?'none':'';
    }
    renderElList(); scheduleAutoSave();
  }

  function initDefaultElements() {
    ['logo','company','address','reg','pan','divider','watermark'].forEach(k=>{
      const el=deepCopy(DEF[k]); el.id=nextId++; elements.push(el); renderElOnPaper(el);
    });
    renderElList();
  }

  // â”€â”€ Expose functions to window for inline HTML handlers â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  function exposeToWindow() {
    window.__lhd_setProp       = setProp;
    window.__lhd_delEl         = delEl;
    window.__lhd_dupEl         = dupEl;
    window.__lhd_addEl         = addEl;
    window.__lhd_loadSave      = loadSave;
    window.__lhd_deleteSave    = deleteSave;
    window.__lhd_saveDesign    = saveDesign;
    window.__lhd_resetAll      = resetAll;
    window.__lhd_downloadHTML  = downloadHTML;
    window.__lhd_toggleGrid    = toggleGrid;
    window.__lhd_setZoom       = setZoom;
    window.__lhd_updatePaper   = updatePaper;
    window.__lhd_switchTab     = switchTab;
    window.__lhd_toggleSec     = toggleSec;
    window.__lhd_uploadImg     = (id,input)=>{ const el=getEl(id);if(!el)return;const f=input.files[0];if(!f)return;const r=new FileReader();r.onload=e=>{el.src=e.target.result;refreshEl(el);scheduleAutoSave();};r.readAsDataURL(f); };
    window.__lhd_resetImg      = id=>{ const el=getEl(id);if(!el)return;el.src=null;refreshEl(el);scheduleAutoSave(); };
    window.__lhd_gradStopColor = (i,v)=>{ const el=getEl(selId);if(!el||!el.grad)return;el.grad.stops[i].c=v;refreshGradPrev(el);refreshEl(el);scheduleAutoSave(); };
    window.__lhd_gradStopPos   = (i,v)=>{ const el=getEl(selId);if(!el||!el.grad)return;el.grad.stops[i].p=v;refreshGradPrev(el);refreshEl(el);scheduleAutoSave(); };
    window.__lhd_addGradStop   = ()=>{ const el=getEl(selId);if(!el||!el.grad)return;el.grad.stops.push({c:'#ffffff',p:50});showProps(selId);refreshEl(el);scheduleAutoSave(); };
    window.__lhd_removeGradStop= i=>{ const el=getEl(selId);if(!el||!el.grad||el.grad.stops.length<2)return;el.grad.stops.splice(i,1);showProps(selId);refreshEl(el);scheduleAutoSave(); };
    window.__lhd_gradType      = v=>{ const el=getEl(selId);if(!el||!el.grad)return;el.grad.type=v;refreshGradPrev(el);refreshEl(el);scheduleAutoSave(); };
    window.__lhd_gradAngle     = v=>{ const el=getEl(selId);if(!el||!el.grad)return;el.grad.angle=v;refreshGradPrev(el);refreshEl(el);scheduleAutoSave(); };
    window.__lhd_applyPreset   = i=>{ const el=getEl(selId);if(!el||!el.grad)return;const pr=PRESETS[i];el.grad.type=pr[1];el.grad.angle=pr[2];el.grad.stops=pr[3].map(s=>({...s}));showProps(selId);refreshEl(el);scheduleAutoSave(); };
  }

  // â”€â”€ HTML Template â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  function buildHTML() {
    return `<div class="lhd-wrap">
<div class="lhd-topbar">
  <div><h2>âœï¸ Letterhead Designer</h2><p>Click to select Â· Drag to move Â· Corner handle to resize Â· Gradient text</p></div>
  <div class="lhd-topbar-r">
    <button class="lhd-btn lhd-btn-o lhd-sm" onclick="window.__lhd_toggleGrid()">âŠž Grid</button>
    <button class="lhd-btn lhd-btn-o lhd-sm" onclick="window.__lhd_resetAll()">â†º Reset</button>
    <button class="lhd-btn lhd-btn-o lhd-sm" onclick="window.print()">ðŸ–¨ Print</button>
    <button class="lhd-btn lhd-btn-g lhd-sm" onclick="window.__lhd_saveDesign()">ðŸ’¾ Save</button>
    <button class="lhd-btn lhd-btn-a lhd-sm" onclick="window.__lhd_downloadHTML()">â¬‡ Download</button>
  </div>
</div>
<div class="lhd-saves-bar"><span>Saved:</span><div class="lhd-save-chips" id="lhd-saveChips"></div></div>
<div class="lhd-main">
  <div class="lhd-sidebar">
    <div class="lhd-stabs">
      <div class="lhd-stab lhd-active" onclick="window.__lhd_switchTab(this,'elements')">Elements</div>
      <div class="lhd-stab" onclick="window.__lhd_switchTab(this,'props')">Properties</div>
      <div class="lhd-stab" onclick="window.__lhd_switchTab(this,'page')">Page</div>
    </div>
    <div id="lhd-tab-elements">
      <div class="lhd-sec">
        <div class="lhd-sec-h" onclick="window.__lhd_toggleSec(this)">Add Element <span class="lhd-arr">â–¼</span></div>
        <div class="lhd-sec-b">
          <div class="lhd-row2" style="margin-bottom:5px;">
            <button class="lhd-btn lhd-btn-o lhd-sm" onclick="window.__lhd_addEl('text')">+ Text</button>
            <button class="lhd-btn lhd-btn-o lhd-sm" onclick="window.__lhd_addEl('company')">+ Company</button>
            <button class="lhd-btn lhd-btn-o lhd-sm" onclick="window.__lhd_addEl('address')">+ Address</button>
            <button class="lhd-btn lhd-btn-o lhd-sm" onclick="window.__lhd_addEl('pan')">+ PAN/VAT</button>
            <button class="lhd-btn lhd-btn-o lhd-sm" onclick="window.__lhd_addEl('reg')">+ Reg. No.</button>
            <button class="lhd-btn lhd-btn-o lhd-sm" onclick="window.__lhd_addEl('divider')">+ Divider</button>
            <button class="lhd-btn lhd-btn-o lhd-sm" onclick="window.__lhd_addEl('logo')">+ Logo</button>
            <button class="lhd-btn lhd-btn-o lhd-sm" onclick="window.__lhd_addEl('watermark')">+ Watermark</button>
          </div>
          <div class="lhd-info"><b>Tip:</b> Click element to select. Drag to move. Pull corner to resize.</div>
        </div>
      </div>
      <div class="lhd-sec">
        <div class="lhd-sec-h" onclick="window.__lhd_toggleSec(this)">All Elements <span class="lhd-arr">â–¼</span></div>
        <div class="lhd-sec-b"><div class="lhd-el-list" id="lhd-elList"></div></div>
      </div>
    </div>
    <div id="lhd-tab-props" style="display:none"><div id="lhd-propPanel"><div style="padding:24px;text-align:center;color:#444;font-size:.82rem;"><div style="font-size:2rem;margin-bottom:8px;">âœï¸</div>Click an element to edit</div></div></div>
    <div id="lhd-tab-page" style="display:none">
      <div class="lhd-sec">
        <div class="lhd-sec-h" onclick="window.__lhd_toggleSec(this)">Paper <span class="lhd-arr">â–¼</span></div>
        <div class="lhd-sec-b">
          <div class="lhd-field"><label>Size</label><select id="lhd-paperSz" class="lhd-si" onchange="window.__lhd_updatePaper()"><option value="lhd-a4" selected>A4 (210mm Ã— 297mm)</option></select></div>
          <div class="lhd-cr"><label>Background</label><input type="color" id="lhd-paperBg" value="#ffffff" oninput="window.__lhd_updatePaper()"></div>
        </div>
      </div>
      <div class="lhd-sec">
        <div class="lhd-sec-h" onclick="window.__lhd_toggleSec(this)">View <span class="lhd-arr">â–¼</span></div>
        <div class="lhd-sec-b">
          <div class="lhd-rr"><div><label>Zoom</label><input type="range" id="lhd-zoomR" min="30" max="120" value="65" oninput="window.__lhd_setZoom(+this.value)"></div><span id="lhd-zoomV">65%</span></div>
          <div class="lhd-tr"><span class="lhd-tl">Show Grid</span><label class="lhd-toggle"><input type="checkbox" id="lhd-gridCb" onchange="window.__lhd_toggleGrid()"><span class="lhd-tsl"></span></label></div>
          <div class="lhd-tr"><span class="lhd-tl">Snap to Grid</span><label class="lhd-toggle"><input type="checkbox" id="lhd-snapCb" checked><span class="lhd-tsl"></span></label></div>
        </div>
      </div>
      <div class="lhd-sec">
        <div class="lhd-sec-h" onclick="window.__lhd_toggleSec(this)">Saved Designs <span class="lhd-arr">â–¼</span></div>
        <div class="lhd-sec-b">
          <div class="lhd-info">Saved to <b>browser localStorage</b> â€” persists across sessions.</div>
          <div id="lhd-savesList2"></div>
          <button class="lhd-btn lhd-btn-g lhd-sm" style="width:100%;margin-top:8px;" onclick="window.__lhd_saveDesign()">ðŸ’¾ Save Current Design</button>
        </div>
      </div>
    </div>
  </div>
  <div class="lhd-canvas-area">
    <div class="lhd-canvas-top">
      <span class="lhd-label">Zoom:</span>
      <button class="lhd-csb" onclick="window.__lhd_setZoom(50)">50%</button>
      <button class="lhd-csb lhd-active" onclick="window.__lhd_setZoom(75)">75%</button>
      <button class="lhd-csb" onclick="window.__lhd_setZoom(100)">100%</button>
      <span class="lhd-hint">ðŸ“ A4 (210mm Ã— 297mm) Â· ðŸŽ¨ Gradient text Â· ðŸ’¾ Auto-saved</span>
    </div>
    <div class="lhd-paper-outer" id="lhd-paperOuter">
      <div class="lhd-paper lhd-a4" id="lhd-paper">
        <svg class="lhd-grid" id="lhd-gridOv" xmlns="http://www.w3.org/2000/svg">
          <defs><pattern id="lhd-gridpat" width="20" height="20" patternUnits="userSpaceOnUse">
            <path d="M20 0L0 0 0 20" fill="none" stroke="#888" stroke-width="0.3"/>
          </pattern></defs>
          <rect width="100%" height="100%" fill="url(#lhd-gridpat)"/>
        </svg>
      </div>
    </div>
  </div>
</div>
</div>`;
  }

  // â”€â”€ Mount â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  function mount() {
    rootEl.innerHTML = buildHTML();
    _paper      = rootEl.querySelector('#lhd-paper');
    _propPanel  = rootEl.querySelector('#lhd-propPanel');
    _elList     = rootEl.querySelector('#lhd-elList');
    _saveChips  = rootEl.querySelector('#lhd-saveChips');
    _savesList2 = rootEl.querySelector('#lhd-savesList2');

    _paper.addEventListener('mousedown', e => {
      if (e.target===_paper||['svg','rect','path'].includes(e.target.tagName)) deselectAll();
    });
    document.addEventListener('mousemove', onMouseMove);
    document.addEventListener('mouseup', onMouseUp);

    exposeToWindow();

    const store = getStore();
    if (store['autosave']) {
      loadState(store['autosave']); currentSaveName='autosave'; showToast('Last session restored');
    } else {
      initDefaultElements();
    }
    renderSavesBar(); renderSavesList2();
    setTimeout(() => setZoom(65), 50);
  }

  return { mount };
}

// â”€â”€â”€ React Component â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function LetterheadDesigner({ className = '', style = {} }) {
  const rootRef = useRef(null);
  const mountedRef = useRef(false);

  useEffect(() => {
    // Inject CSS once
    if (!document.getElementById('lhd-styles')) {
      const styleEl = document.createElement('style');
      styleEl.id = 'lhd-styles';
      styleEl.textContent = WIDGET_CSS;
      document.head.appendChild(styleEl);
    }

    // Inject Google Fonts once
    if (!document.getElementById('lhd-fonts')) {
      const link = document.createElement('link');
      link.id = 'lhd-fonts';
      link.rel = 'stylesheet';
      link.href = 'https://fonts.googleapis.com/css2?family=Montserrat:wght@400;600;700&family=Merriweather:wght@400;700&family=Lato:wght@300;400;700&family=Source+Sans+3:wght@300;400;600&display=swap';
      document.head.appendChild(link);
    }

    // Mount designer
    if (rootRef.current && !mountedRef.current) {
      mountedRef.current = true;
      const designer = createDesigner(rootRef.current);
      designer.mount();
    }

    return () => {
      // Cleanup global handlers on unmount
      delete window.__lhd_setProp;
      delete window.__lhd_addEl;
    };
  }, []);

  return (
    <div
      ref={rootRef}
      className={className}
      style={{ width: '100%', height: '100%', minHeight: '700px', ...style }}
    />
  );
}


// â”€â”€â”€ Letterhead Setup Wrapper â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function LetterheadSetup({ letterheadHtml, saveLetterhead, showToast }) {
  const designerRef = React.useRef(null);
  const [showPreview, setShowPreview] = React.useState(false);
  const [fullscreen, setFullscreen] = React.useState(false);

  const captureAndSave = React.useCallback(async () => {
    const root = designerRef.current;
    if (!root) return;
    const paper = root.querySelector('#lhd-paper');
    if (!paper) { showToast('âš  Designer not ready â€” please wait'); return; }

    showToast('â³ Capturing letterheadâ€¦');

    try {
      // â”€â”€ Detect content height â€” find lowest element bottom â”€â”€
      let contentH = 0;
      paper.querySelectorAll('.lhd-el').forEach(el => {
        const top = parseFloat(el.style.top) || 0;
        const h   = parseFloat(el.style.height) || el.offsetHeight || 0;
        contentH  = Math.max(contentH, top + h + 10);
      });
      const captureH = Math.max(Math.min(contentH, 320), 120);

      // â”€â”€ Load html2canvas from CDN (cached after first load) â”€â”€
      await new Promise((resolve, reject) => {
        if (window.html2canvas) { resolve(); return; }
        const s = document.createElement('script');
        s.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js';
        s.onload = resolve;
        s.onerror = () => reject(new Error('Failed to load html2canvas'));
        document.head.appendChild(s);
      });

      // â”€â”€ Hide resize handles and selection rings before capture â”€â”€
      const rings = paper.querySelectorAll('.lhd-ring, .lhd-rh');
      rings.forEach(r => { r._prevDisplay = r.style.display; r.style.display = 'none'; });

      // â”€â”€ Capture exactly what the user sees â”€â”€
      const canvas = await window.html2canvas(paper, {
        width: paper.offsetWidth,
        height: captureH,
        scale: 1,
        useCORS: true,
        allowTaint: true,
        backgroundColor: paper.style.background || '#ffffff',
        logging: false,
        y: 0,
        x: 0,
      });

      // â”€â”€ Restore handles â”€â”€
      rings.forEach(r => { r.style.display = r._prevDisplay || ''; });

      // â”€â”€ Compress and save â”€â”€
      const dataUrl = canvas.toDataURL('image/jpeg', 0.92);
      await saveLetterhead(dataUrl);
      showToast('âœ… Letterhead saved and active in all reports!');
    } catch(err) {
      console.error('Letterhead capture failed:', err);
      showToast('âš  Capture failed: ' + err.message);
    }
  }, [saveLetterhead, showToast]);

  const wrapStyle = fullscreen ? {
    position:'fixed', top:0, left:0, right:0, bottom:0, zIndex:9999,
    background:'#1a1714', display:'flex', flexDirection:'column'
  } : {
    display:'flex', flexDirection:'column',
    height:'calc(100vh - 110px)', minHeight:'680px'
  };

  // Portal modal rendered outside the component tree to avoid stacking context clipping
  const previewModal = showPreview && letterheadHtml ? (
    <div
      onClick={()=>setShowPreview(false)}
      style={{
        position:'fixed',top:0,left:0,width:'100vw',height:'100vh',
        zIndex:99999,background:'rgba(0,0,0,0.82)',
        display:'flex',alignItems:'center',justifyContent:'center',
        padding:'20px'
      }}>
      <div
        onClick={e=>e.stopPropagation()}
        style={{
          background:'#fff',borderRadius:'12px',width:'100%',maxWidth:'680px',
          maxHeight:'90vh',overflow:'auto',boxShadow:'0 16px 64px rgba(0,0,0,0.6)',
          display:'flex',flexDirection:'column'
        }}>
        <div style={{
          display:'flex',justifyContent:'space-between',alignItems:'center',
          padding:'14px 18px',borderBottom:'1px solid #eee',flexShrink:0
        }}>
          <span style={{fontWeight:700,fontSize:'15px',color:'#2c1810'}}>
            ðŸ“„ Saved Letterhead Preview
          </span>
          <div style={{display:'flex',gap:'8px'}}>
            <button onClick={async ()=>{ await captureAndSave(); setShowPreview(false); }}
              style={{padding:'8px 18px',background:'#2d6a4f',border:'none',color:'#fff',
                borderRadius:'6px',fontWeight:700,fontSize:'13px',cursor:'pointer'}}>
              ðŸ’¾ Re-save Current
            </button>
            <button onClick={()=>setShowPreview(false)}
              style={{padding:'8px 14px',background:'#f5f5f5',border:'1px solid #ddd',
                borderRadius:'6px',fontWeight:600,fontSize:'13px',cursor:'pointer',color:'#333'}}>
              âœ• Close
            </button>
          </div>
        </div>
        <div style={{padding:'16px',flex:1,overflow:'auto'}}>
          <div style={{border:'1px solid #ddd',borderRadius:'8px',overflow:'hidden',background:'#f9f9f9',padding:'8px'}}>
            <div dangerouslySetInnerHTML={{__html: DOMPurify.sanitize(letterheadHtml, {FORCE_BODY:true})}} style={{maxWidth:'100%',display:'block'}} />
          </div>
          <p style={{fontSize:'11px',color:'#888',textAlign:'center',marginTop:'10px',fontStyle:'italic'}}>
            This is how the letterhead will appear in your reports.
          </p>
        </div>
      </div>
    </div>
  ) : null;

  return (
    <React.Fragment>
      {previewModal}
      <div style={wrapStyle}>
        <div style={{
          display:'flex', alignItems:'center', gap:'10px', flexWrap:'wrap',
          padding: fullscreen ? '10px 16px' : '0 0 10px 0',
          background: fullscreen ? '#1a1714' : 'transparent',
          borderBottom: fullscreen ? '1px solid #333' : 'none',
          flexShrink: 0
        }}>
          {!fullscreen && <SectionHeader num="LH" title="Letterhead Setup" />}
          {!fullscreen && <div style={{flex:1}}/>}
          {letterheadHtml ? (
            <div style={{display:'flex',alignItems:'center',gap:'6px',padding:'6px 12px',
              background:'#e8f5e9',border:'1.5px solid #2d6a4f',borderRadius:'20px',
              fontSize:'12px',color:'#2d6a4f',fontWeight:700}}>
              âœ… Letterhead saved
            </div>
          ) : (
            <div style={{display:'flex',alignItems:'center',gap:'6px',padding:'6px 12px',
              background:'#fff8e1',border:'1.5px solid #f4a261',borderRadius:'20px',
              fontSize:'12px',color:'#8b5e00',fontWeight:600}}>
              âš  No letterhead saved yet
            </div>
          )}
          {letterheadHtml && (
            <button onClick={()=>setShowPreview(true)}
              style={{padding:'8px 16px',background:'#fff',border:'1.5px solid var(--accent)',
                color:'var(--accent)',borderRadius:'var(--radius)',fontWeight:600,
                fontSize:'12px',cursor:'pointer',display:'flex',alignItems:'center',gap:'6px'}}>
              ðŸ‘ Preview
            </button>
          )}
          {letterheadHtml && (
            <button onClick={()=>{ saveLetterhead(''); showToast('Letterhead cleared'); }}
              style={{padding:'8px 14px',background:'#fff',border:'1.5px solid #e74c3c',
                color:'#e74c3c',borderRadius:'var(--radius)',fontWeight:600,fontSize:'12px',cursor:'pointer'}}>
              âœ• Clear
            </button>
          )}
          <button onClick={()=>setFullscreen(f=>!f)}
            title={fullscreen ? 'Exit fullscreen' : 'Fullscreen designer'}
            style={{padding:'8px 12px',background:fullscreen?'rgba(255,255,255,0.1)':'var(--surface)',
              border:'1.5px solid var(--border-dark)',color:fullscreen?'#fff':'var(--text-2)',
              borderRadius:'var(--radius)',fontWeight:600,fontSize:'13px',cursor:'pointer'}}>
            {fullscreen ? 'âŠ  Exit' : 'â›¶ Fullscreen'}
          </button>
          <button onClick={captureAndSave}
            style={{padding:'10px 24px',background:'#2d6a4f',border:'none',color:'#fff',
              borderRadius:'var(--radius)',fontWeight:700,fontSize:'13px',cursor:'pointer',
              boxShadow:'0 2px 8px rgba(45,106,79,0.4)',display:'flex',alignItems:'center',gap:'8px',flexShrink:0}}>
            ðŸ’¾ Use in Reports
          </button>
        </div>
        {!fullscreen && (
          <div style={{marginBottom:'8px',flexShrink:0,display:'flex',gap:'16px',
            padding:'8px 12px',background:'var(--surface)',borderRadius:'6px',
            border:'1px solid var(--border)',fontSize:'12px',color:'var(--text-2)',flexWrap:'wrap'}}>
            <span>ðŸ–± <strong>Click</strong> element to select</span>
            <span>âœ‹ <strong>Drag</strong> to move</span>
            <span>â†— <strong>Corner handle</strong> to resize</span>
            <span>ðŸŽ¨ <strong>Gradient text</strong> supported</span>
            <span>ðŸ’¾ <strong>Auto-saved</strong> on every change</span>
          </div>
        )}
        <div ref={designerRef} style={{
          flex:1, borderRadius: fullscreen?'0':'8px',
          overflow:'hidden', boxShadow: fullscreen?'none':'0 2px 16px rgba(0,0,0,0.15)',
          minHeight:0
        }}>
          <LetterheadDesigner style={{height:'100%',minHeight:'100%'}} />
        </div>
      </div>
    </React.Fragment>
  );
}



export default LetterheadSetup;
